def sike_sizes(p_bits: int) -> dict:
    # Approximate formulas based on SIKE spec
    field_bytes = (p_bits + 7) // 8
    pk_bytes = 6 * field_bytes  # Compressed
    ct_bytes = 6 * field_bytes + 16
    return {'pk': pk_bytes, 'ct': ct_bytes, 'total': pk_bytes + ct_bytes}

