exercises.solution:
class SIDHSim:
    def __init__(self, j0: int = 0):
        self.j0 = j0

    def keygen_alice(self, secret: int) -> tuple:
        j_A = (self.j0 + secret * 17) % 10000
        aux = (secret * 3 % 1000, secret * 7 % 1000)
        return (j_A, aux)

    def keygen_bob(self, secret: int) -> tuple:
        j_B = (self.j0 + secret * 23) % 10000
        aux = (secret * 11 % 1000, secret * 13 % 1000)
        return (j_B, aux)

    def shared_secret(self, my_secret: int, their_public: tuple) -> int:
        j, aux = their_public
        return (j + my_secret) % 10000

