exercises.solution:
def auxiliary_info_bits(a: int, q: int) -> int:
    import math
    # Two points over F_q² each have 4 * log2(q) bits
    return int(4 * math.log2(q) * 2)

def is_more_than_curve(aux_bits: int, curve_bits: int) -> bool:
    return aux_bits > curve_bits
